        duration: PTT_CONFIG.FLY_DURATION,
      });
      setTimeout(function () {
        _showStation(station, imageUrl);
      }, PTT_CONFIG.FLY_DURATION * 1000);
      return;
    }
    _showStation(station, imageUrl);
  }

  function _showStation(station, imageUrl) {
    ModalRenderer.showStationModal(station, imageUrl);

