/**
 * ============================================================
 *  PTT Station Map — Route Service (Bing Maps)
 *  Depends on: config.js
 * ============================================================
 */
var RouteService = (function () {
  "use strict";

  var TIMEOUT_MS = 8000;

  function _buildUrl(sLat, sLng, eLat, eLng) {
    return (
      "https://dev.virtualearth.net/REST/V1/Routes/Driving" +
      "?wp.0=" + sLat + "," + sLng +
      "&wp.1=" + eLat + "," + eLng +
      "&optmz=timeWithTraffic&key=" + PTT_CONFIG.BING_MAPS_KEY
    );
  }

  function _fetchWithTimeout(url) {
    return new Promise(function (resolve, reject) {
      var timer = setTimeout(function () {
        reject(new Error("Route request timed out"));
      }, TIMEOUT_MS);

      fetch(url)
        .then(function (r) {
          clearTimeout(timer);
          if (!r.ok) throw new Error("HTTP " + r.status);
          return r.json();
        })
        .then(resolve)
        .catch(function (err) {
          clearTimeout(timer);
          reject(err);
        });
    });
  }

  function _parseRoute(data) {
    if (
      !data ||
      !data.resourceSets ||
      !data.resourceSets[0] ||
      !data.resourceSets[0].resources ||
      data.resourceSets[0].resources.length === 0
    ) {
      throw new Error("No route found");
    }
    return data.resourceSets[0].resources[0];
  }

  /** @returns {Promise<{distance: string, travelTime: string}>} */
  function getRoute(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_buildUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        var route = _parseRoute(data);
        var km = route.travelDistance;
        var secs = route.travelDurationTraffic || route.travelDuration || 0;
        var mins = secs / 60;
        return {
          distance: km.toFixed(1) + " km",
          travelTime: Math.floor(mins / 60) + " hr " + Math.round(mins % 60) + " min",
        };
      });
  }

  /** @returns {Promise<string>} distance in km */
  function getDistance(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_buildUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        var route = _parseRoute(data);
        return route.travelDistance.toFixed(1);
      });
  }

  return { getRoute: getRoute, getDistance: getDistance };
})();

/**
 * ============================================================
 *  PTT Station Map — Route Service
 *  Primary: OSRM (free, no key needed)
 *  Fallback: Bing Maps (if key is valid)
 *  Last resort: straight-line estimate
 *  Depends on: config.js
 * ============================================================
 */
var RouteService = (function () {
  "use strict";

  var TIMEOUT_MS = 6000;
  var AVG_SPEED_KMH = 45; // average Cambodia driving speed for estimate

  // ── Shared helpers ────────────────────────────────────────

  function _fetchWithTimeout(url) {
    return new Promise(function (resolve, reject) {
      var timer = setTimeout(function () {
        reject(new Error("Route request timed out"));
      }, TIMEOUT_MS);

      fetch(url)
        .then(function (r) {
          clearTimeout(timer);
          if (!r.ok) throw new Error("HTTP " + r.status);
          return r.json();
        })
        .then(resolve)
        .catch(function (err) {
          clearTimeout(timer);
          reject(err);
        });
    });
  }

  function _formatTime(totalMinutes) {
    var hrs = Math.floor(totalMinutes / 60);
    var mins = Math.round(totalMinutes % 60);
    if (hrs > 0) {
      return hrs + " hr " + mins + " min";
    }
    return mins + " min";
  }

  // ── OSRM (free, no API key) ───────────────────────────────

  function _osrmUrl(sLat, sLng, eLat, eLng) {
    return (
      "https://router.project-osrm.org/route/v1/driving/" +
      sLng + "," + sLat + ";" + eLng + "," + eLat +
      "?overview=false"
    );
  }

  function _osrmRoute(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_osrmUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        if (!data || data.code !== "Ok" || !data.routes || !data.routes[0]) {
          throw new Error("OSRM: no route");
        }
        var r = data.routes[0];
        var km = r.distance / 1000;       // meters → km
        var mins = r.duration / 60;        // seconds → minutes
        return {
          distance: km.toFixed(1) + " km",
          travelTime: _formatTime(mins),
        };
      });
  }

  function _osrmDistance(startLat, startLng, endLat, endLng) {
    return _fetchWithTimeout(_osrmUrl(startLat, startLng, endLat, endLng))
      .then(function (data) {
        if (!data || data.code !== "Ok" || !data.routes || !data.routes[0]) {
